import{_ as t,o as e,c as r,S as l}from"./chunks/framework.C6RQlTYc.js";const b=JSON.parse('{"title":"React 概述","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/08react/s_react_1-overview.md","filePath":"直击概念/08react/s_react_1-overview.md","lastUpdated":1778207238000}'),d={name:"直击概念/08react/s_react_1-overview.md"};function o(i,a,h,c,n,s){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="react-概述" tabindex="-1">React 概述 <a class="header-anchor" href="#react-概述" aria-label="Permalink to &quot;React 概述&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>React 是 Facebook（Meta）开源的用于构建<strong>用户界面</strong>的 JavaScript 库。它的核心理念是<strong>声明式、组件化、一次学习随处编写</strong>。React 不是框架——它只关注视图层，路由、状态管理等由社区生态补充。</p><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><h3 id="声明式" tabindex="-1">声明式 <a class="header-anchor" href="#声明式" aria-label="Permalink to &quot;声明式&quot;">​</a></h3><p>你只需要描述&quot;界面应该长什么样&quot;，React 负责高效地更新和渲染。当数据变化时，React 自动计算出最小 DOM 操作。</p><h3 id="组件化" tabindex="-1">组件化 <a class="header-anchor" href="#组件化" aria-label="Permalink to &quot;组件化&quot;">​</a></h3><p>UI 被拆分为独立、可复用的组件，每个组件管理自己的状态和渲染逻辑。</p><h3 id="单向数据流" tabindex="-1">单向数据流 <a class="header-anchor" href="#单向数据流" aria-label="Permalink to &quot;单向数据流&quot;">​</a></h3><p>数据从父组件通过 Props 流向子组件，子组件不能直接修改父组件数据，使数据流可预测、易于调试。</p><h2 id="virtual-dom" tabindex="-1">Virtual DOM <a class="header-anchor" href="#virtual-dom" aria-label="Permalink to &quot;Virtual DOM&quot;">​</a></h2><p>React 在内存中维护虚拟 DOM 树，状态变化时：</p><ol><li>生成新虚拟 DOM 树</li><li>与旧的进行 <strong>Diff（差异对比）</strong></li><li>计算最小 DOM 操作集合</li><li>批量更新真实 DOM</li></ol><p>避免直接频繁操作 DOM 带来的性能问题。</p><h2 id="react-vs-vue-vs-angular" tabindex="-1">React vs Vue vs Angular <a class="header-anchor" href="#react-vs-vue-vs-angular" aria-label="Permalink to &quot;React vs Vue vs Angular&quot;">​</a></h2><table><thead><tr><th>维度</th><th>React</th><th>Vue</th><th>Angular</th></tr></thead><tbody><tr><td>类型</td><td>UI 库</td><td>渐进式框架</td><td>完整框架</td></tr><tr><td>数据绑定</td><td>单向</td><td>双向（v-model）</td><td>双向</td></tr><tr><td>状态管理</td><td>社区（Redux/Zustand）</td><td>Pinia</td><td>内置 RxJS</td></tr><tr><td>适用场景</td><td>中大型应用</td><td>快速开发</td><td>企业级</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>React 是框架还是库？为什么这样定位？</li><li>Virtual DOM 的工作流程？解决了什么问题？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://react.dev/" target="_blank" rel="noreferrer">React 官方文档</a></li><li><a href="https://github.com/facebook/react" target="_blank" rel="noreferrer">React GitHub</a></li></ul>',20)])])}const p=t(d,[["render",o]]);export{b as __pageData,p as default};
